/** One level of a dataset's resolution pyramid: a zarr-backed array, with its own voxel-index coordinate system and a stored edge into the dataset's intrinsic space */
export type DataArray = {
  __typename?: 'DataArray';
  chunkShape: Array<Scalars['Int']['output']>;
  /** This level's ARRAY (voxel index) coordinate system */
  coordinateSystem?: Maybe<CoordinateSystem>;
  id: Scalars['ID']['output'];
  level: Scalars['Int']['output'];
  shape: Array<Scalars['Int']['output']>;
  store: ZarrStore;
  /** The edge from this level's voxel space into the dataset's intrinsic space. Its scale is absolute -- derived from the actual shapes, not from a nominal 2**level -- so a pyramid whose axes do not halve cleanly is described correctly */
  toParent?: Maybe<Transformation>;
};

export type DataArrayFilter = {
  AND?: InputMaybe<DataArrayFilter>;
  DISTINCT?: InputMaybe<Scalars['Boolean']['input']>;
  NOT?: InputMaybe<DataArrayFilter>;
  OR?: InputMaybe<DataArrayFilter>;
  /** Filter by the dataset this array belongs to */
  dataset?: InputMaybe<Scalars['ID']['input']>;
  id?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by list of IDs */
  ids?: InputMaybe<Array<Scalars['ID']['input']>>;
  level?: InputMaybe<IntFilterLookup>;
};

export type DataArrayOrder =
  { id: Ordering; level?: never; }
  |  { id?: never; level: Ordering; };

/** A region of interest drawn in a coordinate system. It belongs to that system, not to a scene: delete the scene and the ROI survives */
export type DataRoi = {
  __typename?: 'DataRoi';
  coordinateSystem: CoordinateSystem;
  createdWithTransforms: Scalars['Int']['output'];
  description?: Maybe<Scalars['String']['output']>;
  id: Scalars['UUID']['output'];
  /** The ROI's bounding box in its dataset's intrinsic space, derived from every corner of its geometry (an affine-transformed box is not a box: min/max alone gives a strictly too-small answer under rotation or shear). Intrinsic, not world: world is scene-owned, and one dataset can sit in two scenes under two registrations */
  intrinsicBbox?: Maybe<BoundingBox>;
  kind: RoiKind;
  name: Scalars['String']['output'];
  /** Provenance entries for this data ROI */
  provenanceEntries: Array<ProvenanceEntry>;
  /** The discrete coordinates this ROI is pinned to. An axis the ROI does not pin is one it spans */
  selectors: Array<RoiSelector>;
  vectors: Array<Array<Scalars['Float']['output']>>;
};


/** A region of interest drawn in a coordinate system. It belongs to that system, not to a scene: delete the scene and the ROI survives */
export type DataRoiProvenanceEntriesArgs = {
  pagination?: InputMaybe<OffsetPaginationInput>;
};

export type DataRoiFilter = {
  AND?: InputMaybe<DataRoiFilter>;
  DISTINCT?: InputMaybe<Scalars['Boolean']['input']>;
  NOT?: InputMaybe<DataRoiFilter>;
  OR?: InputMaybe<DataRoiFilter>;
  /** Filter by the coordinate system this ROI is drawn in */
  coordinateSystem?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by the dataset this ROI's coordinate system belongs to, whichever way the system hangs off it (intrinsic, calibration, pyramid level or lens) */
  dataset?: InputMaybe<Scalars['ID']['input']>;
  description?: InputMaybe<StrFilterLookup>;
  id?: InputMaybe<Scalars['UUID']['input']>;
  /** Filter by list of IDs */
  ids?: InputMaybe<Array<Scalars['ID']['input']>>;
  kind?: InputMaybe<RoiKindChoices>;
  name?: InputMaybe<StrFilterLookup>;
  /** Search by name (case-insensitive substring) */
  search?: InputMaybe<Scalars['String']['input']>;
};

export type DataRoiOrder =
  { id: Ordering; name?: never; }
  |  { id?: never; name: Ordering; };

/** A dataset is a collection of images and files. It mimics the concept of a folder in a file system and is the top-level container for organising data in mikro. */
